def fibonacci(n):
    if n < 0:
        return 0
    def matrix_mult(A, B):
        return [
            [A[0][0] * B[0][0] + A[0][1] * B[1][0], A[0][0] * B[0][1] + A[0][1] * B[1][1]],
            [A[1][0] * B[0][0] + A[1][1] * B[1][0], A[1][0] * B[0][1] + A[1][1] * B[1][1]]
        ]
    def matrix_pow(M, p):
        result = [[1, 0], [0, 1]]
        while p:
            if p % 2 == 1:
                result = matrix_mult(result, M)
            M = matrix_mult(M, M)
            p //= 2
        return result
    if n == 0:
        return 0
    result = matrix_pow([[1, 1], [1, 0]], n - 1)
    return result[0][0]

def fibonacci(n):
    if n < 0:
        return 0
    def fast_doubling(n):
        if n == 0:
            return (0, 1)
        a, b = fast_doubling(n >> 1)
        c = a * (2 * b - a)
        d = a * a + b * b
        if n & 1:
            return (d, c + d)
        return (c, d)
    return fast_doubling(n)[0]
